'use client'
import { cn, useControllableSignal, useRovingFocus, useSignals } from '@cascivo/core'
import { useId, type ReactNode } from 'react'
import styles from './structured-list.module.css'

export interface StructuredListItem {
  id: string
  cells: ReactNode[]
  selected?: boolean
}

export interface StructuredListProps {
  items: StructuredListItem[]
  headers?: ReactNode[]
  selectable?: boolean
  value?: string
  defaultValue?: string
  onSelect?: (id: string) => void
  className?: string
  'aria-label'?: string
}

export function StructuredList(props: StructuredListProps) {
  const { items, headers, selectable = false, className, 'aria-label': ariaLabel } = props

  if (selectable) {
    return <SelectableStructuredList {...props} />
  }

  return (
    <div role="table" aria-label={ariaLabel} className={cn(styles['list'], className)}>
      {headers && (
        <div role="row" className={styles['headerRow']}>
          {headers.map((header, i) => (
            <div role="columnheader" key={i} className={styles['headerCell']}>
              {header}
            </div>
          ))}
        </div>
      )}
      <div role="rowgroup" className={styles['body']}>
        {items.map((item) => (
          <div role="row" key={item.id} className={styles['row']}>
            {item.cells.map((cell, i) => (
              <div role="cell" key={i} className={styles['cell']}>
                {cell}
              </div>
            ))}
          </div>
        ))}
      </div>
    </div>
  )
}

function SelectableStructuredList({
  items,
  headers,
  value,
  defaultValue,
  onSelect,
  className,
  'aria-label': ariaLabel,
}: StructuredListProps) {
  useSignals()
  const groupId = useId()
  const [selected, setSelected] = useControllableSignal<string>({
    value,
    defaultValue: defaultValue ?? items.find((item) => item.selected)?.id ?? '',
    onChange: onSelect,
  })
  const roving = useRovingFocus({ orientation: 'vertical', loop: false })

  const select = (id: string) => {
    setSelected(id)
  }

  return (
    <div
      role="radiogroup"
      aria-label={ariaLabel}
      className={cn(styles['list'], styles['selectable'], className)}
    >
      {headers && (
        <div className={styles['headerRow']}>
          <div className={styles['headerCell']} aria-hidden="true" />
          {headers.map((header, i) => (
            <div key={i} className={styles['headerCell']}>
              {header}
            </div>
          ))}
        </div>
      )}
      <div className={styles['body']}>
        {items.map((item, index) => {
          const checked = selected.value === item.id
          const { ref: itemRef, ...rovingProps } = roving.getItemProps(index)
          return (
            <div
              key={item.id}
              role="radio"
              aria-checked={checked}
              aria-labelledby={`${groupId}-${item.id}-label`}
              data-selected={checked || undefined}
              className={styles['row']}
              ref={itemRef}
              {...rovingProps}
              onClick={() => select(item.id)}
              onKeyDown={(event) => {
                rovingProps.onKeyDown(event)
                if (event.key === 'Enter' || event.key === ' ') {
                  event.preventDefault()
                  select(item.id)
                }
              }}
            >
              <div className={styles['cell']} aria-hidden="true">
                <span className={styles['indicator']} />
              </div>
              <div className={styles['cell']} id={`${groupId}-${item.id}-label`}>
                {item.cells[0]}
              </div>
              {item.cells.slice(1).map((cell, i) => (
                <div role="cell" key={i} className={styles['cell']}>
                  {cell}
                </div>
              ))}
            </div>
          )
        })}
      </div>
    </div>
  )
}

@layer cascivo.component {
  .list {
    display: flex;
    flex-direction: column;
    inline-size: 100%;
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .headerRow {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-4);
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .headerCell {
    flex: 1;
    padding-block: var(--cascivo-space-3);
    padding-inline: var(--cascivo-space-4);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text-subtle);
    text-align: start;
  }

  .body {
    display: flex;
    flex-direction: column;
  }

  .row {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-4);
    border-block-start: 1px solid var(--cascivo-color-border);
  }

  .body .row:first-child {
    border-block-start: none;
  }

  .cell {
    flex: 1;
    padding-block: var(--cascivo-space-3);
    padding-inline: var(--cascivo-space-4);
    text-align: start;
  }

  /* Selectable variant */
  .selectable .row {
    cursor: pointer;
    transition: background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &[data-selected] {
      background-color: var(--cascivo-color-bg-subtle);
    }
  }

  /* The leading indicator column for selectable rows is fixed-width. */
  .selectable .row > .cell:first-child,
  .selectable .headerRow > .headerCell:first-child {
    flex: 0 0 auto;
    inline-size: 2.5rem;
  }

  .indicator {
    display: inline-block;
    inline-size: 1rem;
    block-size: 1rem;
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-full, 9999px);

    .row[data-selected] & {
      border-color: var(--cascivo-color-primary);
      border-width: 0.3125rem;
      background-color: var(--cascivo-color-surface);
    }
  }
}

@media (forced-colors: active) {
  .selectable .row:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: -2px;
  }

  .indicator {
    border-color: ButtonText;
  }

  .row[data-selected] .indicator {
    border-color: Highlight;
  }
}
